previewCss:
.darma-loader-darma-custom-245 {
  color: var(--loader-color, #7c3aed);
  height: 27px;
  aspect-ratio: 5;
  --c: currentColor 90deg,#0000 0;
  background:
   conic-gradient(from 135deg at top   ,var(--c)),
   conic-gradient(from -45deg at bottom,var(--c)) 12.5% 100%;
  background-size: 20% 50%;
  background-repeat: repeat-x;
  -webkit-mask: repeating-linear-gradient(90deg,currentColor 0 15%,#0000 0 50%) 0 0/200%;
  animation: darma-loader-darma-custom-245-l6 .8s infinite linear;
}
@keyframes darma-loader-darma-custom-245-l6{
  to {-webkit-mask-position:-100% 0}
}

